import { FeatureCard } from '../../components/ui';
import styles from './page.module.scss';

type Activity = {
  href: string;
  title: string;
  description: string;
  icon: string;
  tag: string;
  tagClass: keyof Pick<typeof styles, 'tagGreen' | 'tagBlue' | 'tagAmber' | 'tagMuted'>;
  disabled?: boolean;
};

export function PracticeActivitiesGrid({ activities }: { activities: Activity[] }) {
  return (
    <div className={styles.grid}>
      {activities.map((activity) => (
        <FeatureCard
          key={activity.title}
          href={activity.disabled ? undefined : activity.href}
          disabled={activity.disabled}
          className={`${styles.card} ${activity.disabled ? styles.cardDisabled : ''}`}
          iconClassName={styles.cardIcon}
          titleClassName={styles.cardTitle}
          descriptionClassName={styles.cardDesc}
          footerClassName={styles.cardFooter}
          title={activity.title}
          description={activity.description}
          icon={activity.icon}
          tag={activity.tag}
          tagVariant={activity.tagClass === 'tagGreen' ? 'green' : activity.tagClass === 'tagBlue' ? 'blue' : activity.tagClass === 'tagAmber' ? 'amber' : 'neutral'}
          cta={<span className={styles.cta}>{activity.disabled ? 'Coming soon' : 'Open →'}</span>}
        />
      ))}
    </div>
  );
}
